import React, { useEffect, useState } from 'react';
import * as Styled from './styles';
import CareerContactSection from '../_sections/CareerContactSection';
import CEOSection from '../_sections/CEOSection';
import useMobile from '../../helpers/hooks/useMobile';
import setLoaderStatus from '../../helpers/functions/setLoaderStatus';

const CareerEmpty = () => {
    const isMobile = useMobile();
    const [isSplineloaded, setIsSplineLoaded] = useState(false);
    
    useEffect(()=> {
        setLoaderStatus(isSplineloaded);
        
        return setLoaderStatus(false);
    },[isSplineloaded])

    return (
        <Styled.CareerPageContainer isMobile={isMobile}>
            <CEOSection
                title='There are no open vacancies in Jito right now'
                subtitle='But we are glad to meet new great people. Drop Jito your CV, and we will contact you shortly.'
            />
            <CareerContactSection setIsSplineLoaded={setIsSplineLoaded}/>
        </Styled.CareerPageContainer>
    );
};

export default CareerEmpty;
